class Solution:
    def numComponents(self, head, nums):
        """
        :type head: Optional[ListNode]
        :type nums: List[int]
        :rtype: int
        """
        num_set = set(nums)
        components = 0
        in_component = False

        current = head
        while current:
            if current.val in num_set:
                if not in_component:
                    components += 1
                    in_component = True
            else:
                in_component = False
            current = current.next

        return components
